esqlQuery.esql:
FROM metrics-vcenterreceiver.otel-*
// VM disk latency max (ms): healthy <20ms; unhealthy >30ms
// Uses max latency per object; use vcenter.vm.disk.latency.avg if available for finer granularity
// Adjust threshold to suit workload
| WHERE vcenter.vm.disk.latency.max IS NOT NULL AND vcenter.vm.disk.latency.max > 20
| STATS latency_ms = MAX(vcenter.vm.disk.latency.max) BY vcenter.datacenter.name, vcenter.cluster.name, vcenter.host.name, vcenter.vm.name, attributes.object
| SORT latency_ms DESC
| LIMIT 20
